# download_datasets.py
# Run: python download_datasets.py
# Creates: raw_data/ folder with all text files

import os
import json
from datasets import load_dataset

os.makedirs("raw_data", exist_ok=True)

# ── DATASET 1: Alpaca GPT4 ──────────────────────────────────────────────────
# 52k high-quality instruction examples generated by GPT-4
# HuggingFace: vicgalle/alpaca-gpt4
# Fixes: instruction following, QA, reasoning (biggest impact)
print("=" * 50)
print("Downloading alpaca-gpt4 (52k examples)...")
try:
    ds = load_dataset("vicgalle/alpaca-gpt4", split="train")
    with open("raw_data/alpaca_gpt4.txt", "w", encoding="utf-8") as f:
        for row in ds:
            inst = row["instruction"].strip()
            inp = row["input"].strip()
            out = row["output"].strip()
            if inp:
                text = f"### Instruction:\n{inst}\n\n### Input:\n{inp}\n\n### Response:\n{out}"
            else:
                text = f"### Instruction:\n{inst}\n\n### Response:\n{out}"
            f.write(text + "\n\n")
    print(f"  [OK] alpaca_gpt4.txt — {len(ds)} examples saved")
except Exception as e:
    print(f"  [FAIL] alpaca-gpt4: {e}")

# ── DATASET 2: Alpaca Cleaned ───────────────────────────────────────────────
# 52k cleaned version of original Alpaca — fixes bad outputs from original
# HuggingFace: yahma/alpaca-cleaned
# Fixes: additional instruction diversity, less hallucinated outputs
print("=" * 50)
print("Downloading alpaca-cleaned (52k examples)...")
try:
    ds2 = load_dataset("yahma/alpaca-cleaned", split="train")
    with open("raw_data/alpaca_cleaned.txt", "w", encoding="utf-8") as f:
        for row in ds2:
            inst = row["instruction"].strip()
            inp = row["input"].strip()
            out = row["output"].strip()
            if inp:
                text = f"### Instruction:\n{inst}\n\n### Input:\n{inp}\n\n### Response:\n{out}"
            else:
                text = f"### Instruction:\n{inst}\n\n### Response:\n{out}"
            f.write(text + "\n\n")
    print(f"  [OK] alpaca_cleaned.txt — {len(ds2)} examples saved")
except Exception as e:
    print(f"  [FAIL] alpaca-cleaned: {e}")

# ── DATASET 3: Wikipedia ────────────────────────────────────────────────────
# English Wikipedia articles — general knowledge, factual text
# HuggingFace: wikimedia/wikipedia (20231101.en)
# Fixes: factual recall, "Paris is capital of France" type failures
# NOTE: streaming=True because full dataset is huge — we take 60k articles only
print("=" * 50)
print("Downloading wikipedia (60k articles, streaming)...")
try:
    ds3 = load_dataset(
        "wikimedia/wikipedia",
        "20231101.en",
        split="train",
        streaming=True,
        trust_remote_code=True
    )
    with open("raw_data/wikipedia.txt", "w", encoding="utf-8") as f:
        count = 0
        for row in ds3:
            text = row["text"].strip()
            if len(text) > 200:  # skip stub articles
                f.write(text + "\n\n")
                count += 1
            if count >= 60000:
                break
            if count % 5000 == 0:
                print(f"    {count}/60000 articles...")
    print(f"  [OK] wikipedia.txt — {count} articles saved")
except Exception as e:
    print(f"  [FAIL] wikipedia: {e}")

# ── DATASET 4: Python Code (The Stack) ─────────────────────────────────────
# Clean Python source files — full functions, not fragmented snippets
# HuggingFace: bigcode/the-stack-smol (data/python subset)
# Fixes: code generation, replaces noisy CodeSearchNet
# NOTE: streaming=True, filter for files > 100 chars to skip empty/tiny files
print("=" * 50)
print("Downloading python code from The Stack (60k files, streaming)...")
try:
    ds4 = load_dataset(
        "bigcode/the-stack-smol",
        data_dir="data/python",
        split="train",
        streaming=True,
        trust_remote_code=True
    )
    with open("raw_data/python_code.txt", "w", encoding="utf-8") as f:
        count = 0
        for row in ds4:
            content = row["content"].strip()
            # Only keep files with meaningful content
            if len(content) > 100 and "def " in content:
                f.write(content + "\n\n")
                count += 1
            if count >= 60000:
                break
            if count % 5000 == 0:
                print(f"    {count}/60000 files...")
    print(f"  [OK] python_code.txt — {count} files saved")
except Exception as e:
    print(f"  [FAIL] the-stack-smol: {e}")
    # Fallback: use CodeParrot Python dataset
    print("  Trying fallback: codeparrot/github-code-clean (Python only)...")
    try:
        ds4b = load_dataset(
            "codeparrot/github-code-clean",
            streaming=True,
            split="train",
            trust_remote_code=True
        )
        with open("raw_data/python_code.txt", "w", encoding="utf-8") as f:
            count = 0
            for row in ds4b:
                if row.get("language", "") == "Python":
                    content = row["code"].strip()
                    if len(content) > 100:
                        f.write(content + "\n\n")
                        count += 1
                if count >= 60000:
                    break
        print(f"  [OK] python_code.txt (fallback) — {count} files saved")
    except Exception as e2:
        print(f"  [FAIL] fallback also failed: {e2}")

# ── DATASET 5: OpenWebText ──────────────────────────────────────────────────
# Cleaned web text — diverse general language
# HuggingFace: Skylion007/openwebtext
# Fixes: general language diversity, web-style text patterns
print("=" * 50)
print("Downloading openwebtext (20k docs, streaming)...")
try:
    ds5 = load_dataset(
        "Skylion007/openwebtext",
        split="train",
        streaming=True,
        trust_remote_code=True
    )
    with open("raw_data/openwebtext.txt", "w", encoding="utf-8") as f:
        count = 0
        for row in ds5:
            text = row["text"].strip()
            if len(text) > 200:
                f.write(text + "\n\n")
                count += 1
            if count >= 20000:
                break
            if count % 2000 == 0:
                print(f"    {count}/20000 docs...")
    print(f"  [OK] openwebtext.txt — {count} docs saved")
except Exception as e:
    print(f"  [FAIL] openwebtext: {e}")

# ── SUMMARY ─────────────────────────────────────────────────────────────────
print("\n" + "=" * 50)
print("DOWNLOAD COMPLETE — checking files:")
for fname in ["alpaca_gpt4.txt", "alpaca_cleaned.txt", "wikipedia.txt",
              "python_code.txt", "openwebtext.txt"]:
    path = f"raw_data/{fname}"
    if os.path.exists(path):
        size_mb = os.path.getsize(path) / (1024 * 1024)
        print(f"  [OK] {fname}: {size_mb:.1f} MB")
    else:
        print(f"  [MISSING] {fname} — check error above")
print("\nNext step: run build_dataset_v3.py")
